<style>
  .np-planet {
    position: relative;
    width: 100%;
    display: block;
    pointer-events: none;
  }
  .np-planet-svg {
    width: 100%;
    height: auto;
    aspect-ratio: 1 / 1;
    display: block;
  }
  .np-planet-svg :global(.np-planet-land) {
    fill: var(--np-planet-land, var(--np-brand));
  }
  .np-planet-svg :global(.np-planet-water) {
    fill: var(--np-planet-water, #2ba8e0);
  }
  .np-planet-svg :global(.np-planet-water-mid) {
    fill: var(--np-planet-water-mid, #1c79a8);
  }
  .np-planet-svg :global(.np-planet-shadow) {
    fill: var(--np-planet-shadow, color-mix(in srgb, var(--np-brand) 55%, #000000 45%));
  }
</style>
